#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <openssl/bn.h>

/*
 * RSA Algorithm Implementation in C
 * Uses OpenSSL BIGNUM for arbitrary precision arithmetic
 * Compile: gcc -o rsa rsa.c -lcrypto
 */

// Structure to hold RSA keys
typedef struct {
    BIGNUM *n;  // Modulus
    BIGNUM *e;  // Public exponent
    BIGNUM *d;  // Private exponent
} RSA_Keys;

// Function prototypes
RSA_Keys* generate_keys(unsigned int bits);
BIGNUM* mod_exp(BIGNUM *base, BIGNUM *exp, BIGNUM *mod);
BIGNUM* mod_inverse(BIGNUM *a, BIGNUM *m);
void encrypt_message(BIGNUM *m, RSA_Keys *keys, BIGNUM **c);
void decrypt_message(BIGNUM *c, RSA_Keys *keys, BIGNUM **m);
void print_bn(char *label, BIGNUM *bn);
void free_keys(RSA_Keys *keys);

// Main demonstration
int main() {
    printf("=================================================\n");
    printf("RSA Algorithm Implementation in C\n");
    printf("Using OpenSSL BIGNUM for big integers\n");
    printf("=================================================\n\n");

    // Initialize OpenSSL BIGNUM context
    BN_CTX *ctx = BN_CTX_new();

    // Generate RSA keys (using small size for demonstration)
    printf("Generating 256-bit RSA keys...\n\n");
    RSA_Keys *keys = generate_keys(256);

    if (keys == NULL) {
        printf("Key generation failed!\n");
        return 1;
    }

    // Print keys
    printf("--- Generated Keys ---\n");
    print_bn("n (modulus): ", keys->n);
    print_bn("e (public exp): ", keys->e);
    print_bn("d (private exp): ", keys->d);

    // Example with textbook values: p=61, q=53
    printf("\n--- Textbook Example: p=61, q=53 ---\n");

    BIGNUM *p = BN_new();
    BIGNUM *q = BN_new();
    BIGNUM *n = BN_new();
    BIGNUM *phi_n = BN_new();
    BIGNUM *e = BN_new();
    BIGNUM *d = BN_new();

    BN_set_word(p, 61);
    BN_set_word(q, 53);

    // n = p * q
    BN_mul(n, p, q, ctx);
    print_bn("n = p*q = ", n);

    // phi_n = (p-1)(q-1)
    BIGNUM *p1 = BN_new();
    BIGNUM *q1 = BN_new();
    BN_sub(p1, p, BN_value_one());
    BN_sub(q1, q, BN_value_one());
    BN_mul(phi_n, p1, q1, ctx);
    print_bn("phi(n) = ", phi_n);

    // e = 17 (public exponent)
    BN_set_word(e, 17);
    print_bn("e = ", e);

    // d = e^(-1) mod phi_n
    d = mod_inverse(e, phi_n);
    print_bn("d = ", d);

    // Encryption: C = M^e mod n
    printf("\n--- Encryption ---\n");
    BIGNUM *M = BN_new();  // Plaintext
    BIGNUM *C = BN_new();  // Ciphertext

    BN_set_word(M, 65);  // ASCII for 'A'
    printf("Plaintext M = 65 (ASCII 'A')\n");

    // C = M^e mod n using BN_modexp
    BN_mod_exp(C, M, e, n, ctx);
    print_bn("Ciphertext C = M^e mod n = ", C);

    // Decryption: M = C^d mod n
    printf("\n--- Decryption ---\n");
    BIGNUM *M_decrypted = BN_new();

    BN_mod_exp(M_decrypted, C, d, n, ctx);
    print_bn("Decrypted M = C^d mod n = ", M_decrypted);

    // Verify
    int match = BN_cmp(M, M_decrypted);
    printf("\nVerification: %s\n", match == 0 ? "SUCCESS!" : "FAILED!");

    // Demonstrate modular exponentiation function
    printf("\n--- Modular Exponentiation Demo ---\n");
    BIGNUM *base = BN_new();
    BIGNUM *exp = BN_new();
    BIGNUM *mod = BN_new();
    BIGNUM *result = BN_new();

    BN_set_word(base, 5);
    BN_set_word(exp, 13);
    BN_set_word(mod, 47);

    result = mod_exp(base, exp, mod);

    printf("5^13 mod 47 = ");
    BN_print_fp(stdout, result);
    printf("\n");

    // Cleanup
    printf("\n--- Cleanup ---\n");
    printf("Freeing all BIGNUM structures...\n");

    BN_free(p);
    BN_free(q);
    BN_free(n);
    BN_free(phi_n);
    BN_free(e);
    BN_free(d);
    BN_free(p1);
    BN_free(q1);
    BN_free(M);
    BN_free(C);
    BN_free(M_decrypted);
    BN_free(base);
    BN_free(exp);
    BN_free(mod);
    BN_free(result);

    free_keys(keys);
    BN_CTX_free(ctx);

    printf("Done!\n");
    return 0;
}

// Generate RSA key pair
RSA_Keys* generate_keys(unsigned int bits) {
    RSA_Keys *keys = (RSA_Keys*)malloc(sizeof(RSA_Keys));
    if (!keys) return NULL;

    BN_CTX *ctx = BN_CTX_new();

    // Generate two random primes
    BIGNUM *p = BN_generate_prime(NULL, bits/2, 0, NULL, NULL, NULL, NULL);
    BIGNUM *q = BN_generate_prime(NULL, bits/2, 0, NULL, NULL, NULL, NULL);

    // n = p * q
    keys->n = BN_new();
    BN_mul(keys->n, p, q, ctx);

    // phi_n = (p-1)(q-1)
    BIGNUM *phi_n = BN_new();
    BIGNUM *p1 = BN_new();
    BIGNUM *q1 = BN_new();
    BN_sub(p1, p, BN_value_one());
    BN_sub(q1, q, BN_value_one());
    BN_mul(phi_n, p1, q1, ctx);

    // e = 65537 (common choice)
    keys->e = BN_new();
    BN_set_word(keys->e, 65537);

    // d = e^(-1) mod phi_n
    keys->d = mod_inverse(keys->e, phi_n);

    // Cleanup
    BN_free(p);
    BN_free(q);
    BN_free(phi_n);
    BN_free(p1);
    BN_free(q1);
    BN_CTX_free(ctx);

    return keys;
}

// Modular exponentiation: result = base^exp mod mod
BIGNUM* mod_exp(BIGNUM *base, BIGNUM *exp, BIGNUM *mod) {
    BN_CTX *ctx = BN_CTX_new();
    BIGNUM *result = BN_new();

    // Use OpenSSL's efficient implementation
    BN_mod_exp(result, base, exp, mod, ctx);

    BN_CTX_free(ctx);
    return result;
}

// Modular inverse: find d such that (a * d) mod m = 1
BIGNUM* mod_inverse(BIGNUM *a, BIGNUM *m) {
    BIGNUM *result = BN_new();

    // Use OpenSSL's modular inverse function
    if (!BN_mod_inverse(result, a, m, NULL)) {
        BN_free(result);
        return NULL;
    }

    return result;
}

// Encrypt message
void encrypt_message(BIGNUM *m, RSA_Keys *keys, BIGNUM **c) {
    BN_CTX *ctx = BN_CTX_new();
    *c = BN_new();

    // C = M^e mod n
    BN_mod_exp(*c, m, keys->e, keys->n, ctx);

    BN_CTX_free(ctx);
}

// Decrypt message
void decrypt_message(BIGNUM *c, RSA_Keys *keys, BIGNUM **m) {
    BN_CTX *ctx = BN_CTX_new();
    *m = BN_new();

    // M = C^d mod n
    BN_mod_exp(*m, c, keys->d, keys->n, ctx);

    BN_CTX_free(ctx);
}

// Print BIGNUM with label
void print_bn(char *label, BIGNUM *bn) {
    printf("%s", label);
    BN_print_fp(stdout, bn);
    printf("\n");
}

// Free RSA keys
void free_keys(RSA_Keys *keys) {
    if (keys) {
        BN_free(keys->n);
        BN_free(keys->e);
        BN_free(keys->d);
        free(keys);
    }
}
